sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual) {
    var table = 'x_1839224_chroma_0_chromatech_sold_products'; 
    var dependentField = 'product_subtype';
    var allPassed = true;
    var finalMessage = "";

    // UPDATE the 'parent' values below with the BACKEND VALUES from your dictionary
    var scenarios = [
        {
            parent: 'air_conditioners', // Example: Use 'air_conditioners' if that's the backend value
            label: 'Air Conditioners',
            expected: ['Central Air Conditioning', 'Portable Air Conditioner', 'Mini Split Air Conditioner', 'Window Air Conditioner']
        },
        {
            parent: 'coolers', // This one passed, so its value likely matches its label
            label: 'Coolers',
            expected: ['Personal Coolers', 'Tower Coolers', 'Desert Coolers', 'Window Coolers']
        },
        {
            parent: 'ceiling_fans', // Example: Use 'ceiling_fans' if that's the backend value
            label: 'Ceiling Fans',
            expected: ['Dual Motor Ceiling Fan', 'Industrial Ceiling Fans', 'Commercial Ceiling Fans']
        }
    ];

    scenarios.forEach(function(scenario) {
        var foundChoices = [];
        var choiceGr = new GlideRecord('sys_choice');
        choiceGr.addQuery('name', table);
        choiceGr.addQuery('element', dependentField);
        choiceGr.addQuery('dependent_value', scenario.parent); // Filters by backend value
        choiceGr.addQuery('inactive', false);
        choiceGr.query();

        while (choiceGr.next()) {
            foundChoices.push(choiceGr.label.getDisplayValue());
        }

        var scenarioPassed = (foundChoices.length === scenario.expected.length);
        scenario.expected.forEach(function(item) {
            if (foundChoices.indexOf(item) === -1) scenarioPassed = false;
        });

        if (scenarioPassed) {
            finalMessage += "PASS: " + scenario.label + " correctly displays all " + scenario.expected.length + " subtypes.\n";
        } else {
            allPassed = false;
            finalMessage += "FAIL: " + scenario.label + ". Expected [" + scenario.expected.join(', ') + "] but found [" + foundChoices.join(', ') + "]. Check if dependent_value is '" + scenario.parent + "'\n";
        }
    });

    stepResult.setOutputMessage(finalMessage);
    if (allPassed) {
        stepResult.setSuccess();
    } else {
        stepResult.setFailed();
    }
})(outputs, steps, stepResult, assertEqual);
